const body = $json.body || $json;
const topic = body.topic || '';
const jiraProject = body.jiraProject || 'CER';
const issuePattern = new RegExp(`${jiraProject}-(\\d+)`, 'gi');
const mentionedIssues = [...new Set((topic.match(issuePattern) || []).map(k => k.toUpperCase()))];

return [{ json: {
  mentionedIssues,
  jiraProject,
  confluenceSpace: body.confluenceSpace || 'CE',
  confluenceParentPage: body.confluenceParentPage || 'Meetings',
  topic,
  sprintJql: `project = ${jiraProject} AND sprint in openSprints() AND status != Done ORDER BY priority DESC`,
  resolvedJql: `project = ${jiraProject} AND status changed to Done AFTER -7d ORDER BY updated DESC`
} }];

// Merge sprint + resolved data with Build Queries context
const queries = $('Build Queries').first()?.json || {};
const sprintData = $('Jira Active Sprint').first()?.json || {};
const resolvedData = $json || {};

let context = '';

// === JIRA ACTIVE SPRINT ===
context += '## Current Jira Sprint Issues\n';
const sprintIssues = sprintData.issues || [];
if (sprintIssues.length > 0) {
  for (const issue of sprintIssues) {
    const f = issue.fields || {};
    const status = f.status?.name || 'Unknown';
    const priority = f.priority?.name || 'Medium';
    const assignee = f.assignee?.displayName || 'Unassigned';
    const labels = (f.labels || []).join(', ');
    context += `- **${issue.key}**: ${f.summary || 'No summary'} | Status: ${status} | Priority: ${priority} | Assignee: ${assignee}${labels ? ` | Labels: ${labels}` : ''}\n`;
  }
} else {
  context += '_No active sprint issues found._\n';
}

// === RECENTLY RESOLVED ===
context += '\n## Recently Resolved (last 7 days)\n';
const resolvedIssues = resolvedData.issues || [];
if (resolvedIssues.length > 0) {
  for (const issue of resolvedIssues) {
    const f = issue.fields || {};
    context += `- **${issue.key}**: ${f.summary || 'No summary'} | Status: DONE | Resolved: ${f.resolutiondate ? new Date(f.resolutiondate).toLocaleDateString() : 'recently'}\n`;
  }
} else {
  context += '_No recently resolved issues._\n';
}

// === MENTIONED ISSUES ===
if (queries.mentionedIssues?.length > 0) {
  context += `\n## Issues Mentioned in Topic\n`;
  context += `The following issues were explicitly mentioned: ${queries.mentionedIssues.join(', ')}\n`;
  context += `Check the Active Sprint and Recently Resolved sections above for their CURRENT status.\n`;
  context += `If an issue appears in Recently Resolved, it is DONE — do not discuss it as open.\n`;
}

return [{ json: { context } }];

// Meshwork webhook caller verification.
// Accepts EITHER:
//   1) the runner's HMAC signature (x-meshwork-signature over `${ts}.${body}`)
//   2) a shared token in ?token= or the x-webhook-token header (for external
//      callers like Jira webhook URLs)
// Enforcement is off until WEBHOOK_VERIFICATION_ENFORCE=true in .env (values
// are substituted at import time by scripts/import-workflows.sh).
const crypto = require('crypto');

const ENFORCE = '{{WEBHOOK_VERIFICATION_ENFORCE}}'.toLowerCase() === 'true';
const RUNNER_SECRET = '{{RUNNER_SECRET}}';
const SHARED_TOKEN = '{{WEBHOOK_SHARED_TOKEN}}';

const item = $input.first().json;
const headers = item.headers || {};
const query = item.query || {};
const body = item.body ?? {};

const isPlaceholder = (v) => !v || v.indexOf('{{') === 0;
let ok = false;

// 1) Runner HMAC
const sig = headers['x-meshwork-signature'];
const ts = headers['x-meshwork-timestamp'];
if (sig && ts && !isPlaceholder(RUNNER_SECRET)) {
  const age = Math.abs(Date.now() - Number(ts));
  if (age < 5 * 60 * 1000) {
    const expected = 'sha256=' + crypto.createHmac('sha256', RUNNER_SECRET)
      .update(ts + '.' + JSON.stringify(body)).digest('hex');
    const a = crypto.createHash('sha256').update(expected).digest();
    const b = crypto.createHash('sha256').update(String(sig)).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

// 2) Shared token
if (!ok && !isPlaceholder(SHARED_TOKEN)) {
  const provided = String(query.token || headers['x-webhook-token'] || '');
  if (provided) {
    const a = crypto.createHash('sha256').update(provided).digest();
    const b = crypto.createHash('sha256').update(SHARED_TOKEN).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

if (!ok && ENFORCE) {
  throw new Error('Webhook verification failed: missing or invalid signature/token. See SECURITY.md (webhook verification).');
}

return $input.all();
